  padding-right: 2px;
}

.gv-aistudio .gv-folder-list {
  padding-left: 0;
  padding-right: 0;
}

/* Make action buttons absolute so they don’t steal inline space */
.gv-aistudio .gv-folder-pin-btn,
.gv-aistudio .gv-folder-actions-btn {
  width: 24px;
  height: 24px;
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  margin: 0;
  overflow: visible;
  z-index: 1;
}

/* Pin button: hidden by default, show on hover to save space */
.gv-aistudio .gv-folder-pin-btn {
  opacity: 0;
  transition: opacity 0.15s ease;
}

/* More button: hidden by default, show on hover to save space */
.gv-aistudio .gv-folder-actions-btn {
  opacity: 0;
  transition: opacity 0.15s ease;
}

.gv-aistudio .gv-folder-item-header:hover .gv-folder-pin-btn,
.gv-aistudio .gv-folder-item-header:hover .gv-folder-actions-btn {
  opacity: 1;
}

.gv-aistudio .gv-folder-actions-btn {
  right: 6px;
}

.gv-aistudio .gv-folder-pin-btn {
  right: 28px;
}

.gv-aistudio .gv-folder-header-actions .gv-folder-action-btn {
  padding: 2px;
}

/* Ensure pin/more icons are perfectly centered and not clipped */
.gv-aistudio .gv-folder-pin-btn .google-symbols,
.gv-aistudio .gv-folder-actions-btn .google-symbols {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  /* match button box */
  height: 24px;
  line-height: 24px;
  overflow: visible !important;
  /* never clip emoji */
}

.gv-aistudio .gv-folder-pin-btn .google-symbols::before,
.gv-aistudio .gv-folder-actions-btn .google-symbols::before {
  width: 24px;
  height: 24px;
  line-height: 24px;
  text-align: center;
  font-size: 20px;
  /* slightly larger for better visual balance */
}

/* Icon fallbacks: hide ligature text and use simple glyphs */
.gv-aistudio .gv-folder-pin-btn .google-symbols,
.gv-aistudio .gv-folder-add-btn .google-symbols,
.gv-aistudio .gv-folder-actions-btn .google-symbols,
.gv-aistudio .gv-folder-expand-btn .google-symbols,
.gv-aistudio .gv-folder-icon.google-symbols,
.gv-aistudio .gv-conversation-icon.google-symbols,
.gv-aistudio .gv-folder-action-btn .google-symbols,
.gv-aistudio .gv-conversation-star-btn .google-symbols,
.gv-aistudio .gv-conversation-remove-btn .google-symbols,
.gv-aistudio .gv-folder-uncategorized-header .google-symbols {
  font-family: inherit !important;
  /* Don’t rely on Material Symbols in aistudio */
  font-weight: 400;
  font-size: 0;
  /* Hide text like 'push_pin' */
  line-height: 20px;
  display: inline-block;
  width: 20px;
  /* bigger box to avoid clipping */
  height: 20px;
  overflow: hidden;
  vertical-align: middle;
}

.gv-aistudio .google-symbols::before {
  display: block;
  width: 20px;
  height: 20px;
  line-height: 20px;
  text-align: center;
  font-size: 18px;
}

/* Per-icon mappings */
.gv-aistudio .google-symbols[data-icon='expand_more']::before {
  content: '▾';
