import React from 'react';

import { Button } from './ui/button';

/** Sends a message to the active Gemini tab to toggle its page theme. */
async function sendPageThemeToggle(): Promise<void> {
  try {
    const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });
    if (!tab?.id) return;
    await chrome.tabs.sendMessage(tab.id, { type: 'gv.pageTheme.toggle' });
  } catch {
    // Silently ignore — tab may not be a Gemini page or content script not ready.
  }
}

export const PageThemeToggle: React.FC = () => {
  return (
    <Button
      variant="ghost"
      size="icon"
      onClick={sendPageThemeToggle}
      title="Toggle page theme"
      className="h-9 w-9"
    >
      {/* Half-filled circle: universal "contrast / theme" icon */}
