/**
 * Page-level theme toggle with circle-expand animation.
 * Triggered by a message from the popup (`gv.pageTheme.toggle`).
 *
 * The View Transition API is used to animate the theme change on the Gemini
 * page itself — this is separate from the popup's own dark mode transition.
 */

/** Common selectors for Gemini's native theme toggle button. */
const THEME_BUTTON_SELECTORS = [
  '[aria-label="Switch to dark theme"]',
  '[aria-label="Switch to light theme"]',
  '[aria-label="Dark theme"]',
  '[aria-label="Light theme"]',
  'button[aria-label*="theme" i]',
  '[data-theme-toggle]',
];

function isPageDark(): boolean {
  return (
    document.documentElement.hasAttribute('dark') ||
    document.body.classList.contains('dark-theme') ||
    document.body.getAttribute('data-theme') === 'dark' ||
    document.documentElement.getAttribute('data-theme') === 'dark'
  );
}

function performThemeChange(): void {
  // Prefer clicking Gemini's native theme toggle so the app state stays in sync.
  for (const selector of THEME_BUTTON_SELECTORS) {
    const el = document.querySelector<HTMLElement>(selector);
    if (el) {
      el.click();
      return;
    }
  }

  // Fallback: direct DOM manipulation (best-effort; may be overridden by Gemini).
  const html = document.documentElement;
  const isDark = isPageDark();
  if (isDark) {
    html.removeAttribute('dark');
    document.body.classList.remove('dark-theme');
    document.body.setAttribute('data-theme', 'light');
    html.setAttribute('data-theme', 'light');
  } else {
    html.setAttribute('dark', '');
    document.body.classList.add('dark-theme');
    document.body.setAttribute('data-theme', 'dark');
    html.setAttribute('data-theme', 'dark');
  }
}

export function startPageThemeToggle(): void {
  chrome.runtime.onMessage.addListener((message) => {
    if (message.type !== 'gv.pageTheme.toggle') return false;

    const startViewTransition = (
      document as {
        startViewTransition?: (cb: () => void) => { ready: Promise<void> };
      }
    ).startViewTransition;

    if (
      !startViewTransition ||
      window.matchMedia('(prefers-reduced-motion: reduce)').matches
    ) {
      performThemeChange();
      return false;
    }

    const x = window.innerWidth / 2;
    const y = window.innerHeight / 2;
    const endRadius = Math.hypot(
      Math.max(x, window.innerWidth - x),
      Math.max(y, window.innerHeight - y),
    );

    const transition = startViewTransition.call(document, performThemeChange);

    transition.ready.then(() => {
      document.documentElement.animate(
        {
          clipPath: [
            `circle(0px at ${x}px ${y}px)`,
            `circle(${endRadius}px at ${x}px ${y}px)`,
          ],
        },
        {
          duration: 500,
          easing: 'ease-in-out',
          pseudoElement: '::view-transition-new(root)',
        },
      );
    });

    return false;
  });
}

