/**
 * Page-level theme toggle with circle-expand animation.
 * Triggered by a message from the popup (`gv.pageTheme.toggle`).
 *
 * Gemini's theme is a 3-way dropdown (System / Light / Dark) rendered as a
 * Material menu. The flow:
 *   1. Find and click the trigger button to open the menu.
 *   2. Wait for the `mat-mdc-menu-panel` to appear in the DOM.
 *   3. Click the target item (index 1 = Light, index 2 = Dark).
 *   4. All of this runs inside `document.startViewTransition()` so the
 *      browser captures before/after screenshots and animates between them.
 *
 * If the trigger button cannot be found, we fall back to direct DOM
 * manipulation which at least produces the visual animation for the
 * current session (the change may not persist across reloads).
 */

// ─── Theme-menu item positions (order: System=0, Light=1, Dark=2) ─────────────
const THEME_INDEX_LIGHT = 1;
const THEME_INDEX_DARK = 2;

// ─── Possible selectors for the button that opens Gemini's theme menu ─────────
// Add / update these as Gemini's DOM evolves.
const THEME_TRIGGER_SELECTORS = [
  '[aria-label="Theme"]',
  '[aria-label="Appearance"]',
  '[aria-label*="theme" i]',
  '[aria-label*="appearance" i]',
  '[data-test-id="theme-trigger"]',
  '[data-test-id="appearance-trigger"]',
];

// ─── Helpers ──────────────────────────────────────────────────────────────────

function isPageDark(): boolean {
  return (
    document.documentElement.hasAttribute('dark') ||
